## What

Create UnixDatagram type for Unix domain datagram sockets, useful for message-oriented local IPC.

## Location

`src/net/unix/datagram.rs` (new file)

## Design

```rust
use std::os::unix::net::{self, SocketAddr};
use std::path::Path;

/// A Unix domain datagram socket.
pub struct UnixDatagram {
    inner: net::UnixDatagram,
    registration: Option<Registration>,
    path: Option<PathBuf>, // For cleanup on drop
}

impl UnixDatagram {
    /// Bind to a filesystem path.
    pub async fn bind<P: AsRef<Path>>(path: P) -> io::Result<Self> {
        let path = path.as_ref();

        // Remove existing socket file
        let _ = std::fs::remove_file(path);

        let inner = net::UnixDatagram::bind(path)?;
        inner.set_nonblocking(true)?;

        let cx = Cx::current();
        let registration = cx.register_io(
            &UnixDatagramSource(&inner),
            Interest::READABLE | Interest::WRITABLE,
        )?;

        Ok(Self {
            inner,
            registration: Some(registration),
            path: Some(path.to_path_buf()),
        })
    }

    /// Create an unbound socket.
    pub fn unbound() -> io::Result<Self> {
        let inner = net::UnixDatagram::unbound()?;
        inner.set_nonblocking(true)?;

        let cx = Cx::current();
        let registration = cx.register_io(
            &UnixDatagramSource(&inner),
            Interest::READABLE | Interest::WRITABLE,
        )?;

        Ok(Self {
            inner,
            registration: Some(registration),
            path: None,
        })
    }

    /// Create a connected pair.
    pub fn pair() -> io::Result<(Self, Self)> {
        let (a, b) = net::UnixDatagram::pair()?;
        a.set_nonblocking(true)?;
        b.set_nonblocking(true)?;

        let cx = Cx::current();

        let reg_a = cx.register_io(&UnixDatagramSource(&a), Interest::READABLE | Interest::WRITABLE)?;
        let reg_b = cx.register_io(&UnixDatagramSource(&b), Interest::READABLE | Interest::WRITABLE)?;

        Ok((
            Self { inner: a, registration: Some(reg_a), path: None },
            Self { inner: b, registration: Some(reg_b), path: None },
        ))
    }

    /// Connect to a specific peer.
    pub fn connect<P: AsRef<Path>>(&self, path: P) -> io::Result<()> {
        self.inner.connect(path)
    }

    /// Send a datagram to a specific address.
    pub async fn send_to<P: AsRef<Path>>(&self, buf: &[u8], path: P) -> io::Result<usize> {
        poll_fn(|cx| self.poll_send_to(cx, buf, path.as_ref())).await
    }

    fn poll_send_to(&self, cx: &mut Context<'_>, buf: &[u8], path: &Path) -> Poll<io::Result<usize>> {
        match self.inner.send_to(buf, path) {
            Ok(n) => Poll::Ready(Ok(n)),
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    /// Receive a datagram with sender address.
    pub async fn recv_from(&self, buf: &mut [u8]) -> io::Result<(usize, SocketAddr)> {
        poll_fn(|cx| self.poll_recv_from(cx, buf)).await
    }

    fn poll_recv_from(&self, cx: &mut Context<'_>, buf: &mut [u8]) -> Poll<io::Result<(usize, SocketAddr)>> {
        match self.inner.recv_from(buf) {
            Ok(result) => Poll::Ready(Ok(result)),
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    /// Send to connected peer.
    pub async fn send(&self, buf: &[u8]) -> io::Result<usize> {
        poll_fn(|cx| self.poll_send(cx, buf)).await
    }

    fn poll_send(&self, cx: &mut Context<'_>, buf: &[u8]) -> Poll<io::Result<usize>> {
        match self.inner.send(buf) {
            Ok(n) => Poll::Ready(Ok(n)),
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    /// Receive from connected peer.
    pub async fn recv(&self, buf: &mut [u8]) -> io::Result<usize> {
        poll_fn(|cx| self.poll_recv(cx, buf)).await
    }

    fn poll_recv(&self, cx: &mut Context<'_>, buf: &mut [u8]) -> Poll<io::Result<usize>> {
        match self.inner.recv(buf) {
            Ok(n) => Poll::Ready(Ok(n)),
            Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.inner.local_addr()
    }

    pub fn peer_addr(&self) -> io::Result<SocketAddr> {
        self.inner.peer_addr()
    }
}

impl Drop for UnixDatagram {
    fn drop(&mut self) {
        if let Some(path) = &self.path {
            let _ = std::fs::remove_file(path);
        }
    }
}
